use mylib::{compact_context, Message};

#[test]
fn test_keeps_recent_messages() {
    let msgs: Vec<Message> = (0..30)
        .map(|i| Message {
            role: "user".to_string(),
            content: format!("message {}", i),
        })
        .collect();

    let result = compact_context(msgs, 20);
    assert!(result.len() <= 20, "Should keep at most 20 messages");
    // Last messages should be preserved
    assert!(result.last().map(|m| m.content.contains("29")).unwrap_or(false));
}

#[test]
fn test_removes_duplicates() {
    let msgs = vec![
        Message { role: "system".to_string(), content: "You are a helpful assistant.".to_string() },
        Message { role: "system".to_string(), content: "You are a helpful assistant.".to_string() },
        Message { role: "user".to_string(), content: "Hello".to_string() },
    ];

    let result = compact_context(msgs, 10);
    let system_count = result.iter().filter(|m| m.role == "system").count();
    assert_eq!(system_count, 1, "Should have at most 1 system message");
}
